// =====================================================
// 核心业务逻辑 (混淆压缩版)
// 此文件包含 ENS 查询的核心功能
// =====================================================

const app = (function() {
    'use strict';
    
    // 私有变量
    let _apiKey = null;
    let _queryHistory = [];
    let _isProcessing = false;
    
    // 配置
    const CONFIG = {
        API_BASE: '/api',
        MAX_HISTORY: 10,
        TIMEOUT: 10000
    };
    
    // 工具函数
    function _(id) { return document.getElementById(id); }
    
    function showLoader(show) {
        const loader = _('loader');
        if (loader) loader.style.display = show ? 'block' : 'none';
    }
    
    function showError(msg) {
        const area = _('result-area');
        if (!area) return;
        area.innerHTML = `<div style="color:#ef4444;padding:1rem;background:rgba(239,68,68,0.1);border-radius:8px;">❌ ${msg}</div>`;
    }
    
    function showResult(data) {
        const area = _('result-area');
        if (!area) return;
        
        let html = '<div style="background:#1e293b;border-radius:12px;padding:1.5rem;">';
        
        if (data.address) {
            html += `<div style="margin-bottom:1rem;"><span style="color:#94a3b8;font-size:0.875rem;">地址</span><div style="color:#3b82f6;font-family:monospace;font-size:1.125rem;word-break:break-all;">${data.address}</div></div>`;
        }
        
        if (data.contentHash) {
            html += `<div style="margin-bottom:1rem;"><span style="color:#94a3b8;font-size:0.875rem;">内容哈希</span><div style="color:#10b981;font-family:monospace;">${data.contentHash}</div></div>`;
        }
        
        if (data.textRecords && Object.keys(data.textRecords).length > 0) {
            html += '<div><span style="color:#94a3b8;font-size:0.875rem;">文本记录</span>';
            for (const [key, value] of Object.entries(data.textRecords)) {
                html += `<div style="display:flex;justify-content:space-between;padding:0.5rem 0;border-bottom:1px solid #334155;"><span style="color:#e2e8f0;">${key}</span><span style="color:#94a3b8;word-break:break-all;max-width:60%;">${value}</span></div>`;
            }
            html += '</div>';
        }
        
        html += '</div>';
        area.innerHTML = html;
    }
    
    // 主查询函数
    async function query(domain) {
        if (_isProcessing) return;
        if (!domain || !domain.includes('.')) {
            showError('请输入有效的域名');
            return;
        }
        
        _isProcessing = true;
        showLoader(true);
        _('result-area').innerHTML = '';
        
        try {
            // 调用后端 API (核心逻辑在服务器端)
            const response = await fetch(`${CONFIG.API_BASE}/rpc?domain=${encodeURIComponent(domain)}`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ domain })
            });
            
            if (!response.ok) {
                throw new Error(`HTTP ${response.status}`);
            }
            
            const result = await response.json();
            
            if (result.success) {
                showResult(result.data);
                addToHistory(domain, result.data);
            } else {
                showError(result.message || '查询失败');
            }
        } catch (error) {
            console.error('Query error:', error);
            showError('网络错误，请稍后重试');
        } finally {
            _isProcessing = false;
            showLoader(false);
        }
    }
    
    // 添加到历史记录
    function addToHistory(domain, data) {
        _queryHistory.unshift({ domain, data, time: new Date().toISOString() });
        if (_queryHistory.length > CONFIG.MAX_HISTORY) {
            _queryHistory.pop();
        }
        renderHistory();
    }
    
    // 渲染历史记录
    function renderHistory() {
        // 简化版，实际可展开
    }
    
    // 初始化查询
    function initQuery() {
        const input = _('domainInput');
        if (input && input.value.trim()) {
            query(input.value.trim());
        }
    }
    
    // 公开接口
    return {
        initQuery,
        query
    };
})();

// 绑定回车键查询
document.addEventListener('DOMContentLoaded', function() {
    const input = document.getElementById('domainInput');
    if (input) {
        input.addEventListener('keypress', function(e) {
            if (e.key === 'Enter') {
                app.initQuery();
            }
        });
    }
});
